import React, { useState } from 'react';
import axios from 'axios';

export default function Detector() {
  const [file, setFile] = useState(null);
  const [mode, setMode] = useState('classification');
  const [data, setData] = useState(null);

  const uploadAndAnalyze = async () => {
    const formData = new FormData();
    formData.append('file', file);
    formData.append('mode', mode);

    const res = await axios.post('http://localhost:5000/analyze', formData);
    setData(res.data);
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial' }}>
      <h2>NeuroScanAI Hub</h2>
      
      {/* Selection Mode */}
      <select onChange={(e) => setMode(e.target.value)} value={mode}>
        <option value="classification">Fast Classification (H5)</option>
        <option value="segmentation">U-Net Segmentation (Keras)</option>
      </select>

      <input type="file" onChange={(e) => setFile(e.target.files[0])} />
      
      <button onClick={uploadAndAnalyze} disabled={!file}>Run Analysis</button>

      {data && (
        <div style={{ marginTop: '20px', border: '1px solid #ccc', padding: '10px' }}>
          <h4>Analysis result using {mode}:</h4>
          <pre>{JSON.stringify(data, null, 2)}</pre>
        </div>
      )}
    </div>
  );
}
